import torch
import torch.nn as nn
import torch.optim as optim
from torch.utils.data import Dataset, DataLoader
import requests
import hashlib
import os
from urllib.parse import urlparse
import tempfile

class CustomDataset(Dataset):
    def __init__(self, data, labels):
        self.data = data
        self.labels = labels
    
    def __len__(self):
        return len(self.data)
    
    def __getitem__(self, idx):
        return self.data[idx], self.labels[idx]

def download_model_from_url(url, expected_hash=None):
    """Download model from URL with optional hash verification"""
    try:
        response = requests.get(url, timeout=30)
        response.raise_for_status()
        
        if expected_hash:
            actual_hash = hashlib.sha256(response.content).hexdigest()
            if actual_hash != expected_hash:
                raise ValueError("Model hash verification failed")
        
        # Save to temporary file
        temp_file = tempfile.NamedTemporaryFile(delete=False, suffix='.pt')
        temp_file.write(response.content)
        temp_file.flush()
        temp_file.close()
        
        return temp_file.name
    except Exception as e:
        raise Exception(f"Failed to download model: {str(e)}")

def load_model_from_url(url, expected_hash=None, map_location='cpu'):
    """Securely load model from URL"""
    try:
        # Validate URL
        parsed_url = urlparse(url)
        if not parsed_url.scheme or not parsed_url.netloc:
            raise ValueError("Invalid URL")
        
        # Download model
        model_path = download_model_from_url(url, expected_hash)
        
        # Load model with security restrictions
        model = torch.load(model_path, map_location=map_location, weights_only=True)
        
        # Clean up temporary file
        os.unlink(model_path)
        
        return model
    except Exception as e:
        raise Exception(f"Failed to load model: {str(e)}")

def fine_tune_model(model, train_loader, val_loader, num_epochs=5, learning_rate=1e-4):
    """Fine-tune model on custom dataset"""
    device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')
    model.to(device)
    
    # Freeze early layers for transfer learning
    for param in list(model.parameters())[:-20]:
        param.requires_grad = False
    
    # Define loss and optimizer
    criterion = nn.CrossEntropyLoss()
    optimizer = optim.Adam(filter(lambda p: p.requires_grad, model.parameters()), 
                          lr=learning_rate)
    
    # Training loop
    model.train()
    for epoch in range(num_epochs):
        total_loss = 0
        for inputs, labels in train_loader:
            inputs, labels = inputs.to(device), labels.to(device)
            
            optimizer.zero_grad()
            outputs = model(inputs)
            loss = criterion(outputs, labels)
            loss.backward()
            optimizer.step()
            
            total_loss += loss.item()
        
        print(f'Epoch [{epoch+1}/{num_epochs}], Loss: {total_loss/len(train_loader):.4f}')
    
    # Validation
    model.eval()
    correct = 0
    total = 0
    with torch.no_grad():
        for inputs, labels in val_loader:
            inputs, labels = inputs.to(device), labels.to(device)
            outputs = model(inputs)
            _, predicted = torch.max(outputs, 1)
            total += labels.size(0)
            correct += (predicted == labels).sum().item()
    
    accuracy = 100 * correct / total
    print(f'Validation Accuracy: {accuracy:.2f}%')
    
    return model

